   127→
   128→    const userId = user?.userData?.[0]?.id || null;
   129→
   130→    const {
   131→        data,
   132→        fetchNextPage,
   133→        hasNextPage,
   134→        isFetchingNextPage,
   135→        isLoading,
   136→    } = useInfiniteQuery({
   137→        queryKey: ['journals', userId],
   138→        queryFn: ({pageParam = null}) => getJournals(pageParam, 5, userId),
   139→        getNextPageParam: (lastPage) => {
   140→            if(lastPage?.hasMore) {
   141→                const lastJournal = lastPage?.data[lastPage?.data?.length - 1]; //get the last array of object using index
   142→                return new Date(lastJournal.created_at).toISOString();
   143→            }
   144→            return undefined;
   145→        } ,
   146→        refetchOnWindowFocus: false
   147→    })
   148→
   149→    const handleClickSettings = (e, postId) =>{
   150→        e.stopPropagation();
   151→        setPostIdSettings(postId === postIdSettings ? null : postId)
   152→    }
   153→
   154→    const mutationLike = useLikeMutation(session, user?.userData?.[0]?.id);
   155→
   156→    const handleClickLike = async(e, journalId, receiverId) => {
   157→        e.stopPropagation();
   158→        if(!session) return openAuthModal();
   159→        console.log(journalId)
   160→        mutationLike.mutate({journalId, receiverId}) //passing this into mutationFn {journalId: the id}
   161→    }
   162→    const debounceClickLike = debounce(handleClickLike, 300)
   163→
   164→
   165→    const mutationBookmark = useBookMarkMutation(session);
   166→
   167→    const handleClickBookmark = async(e, journalId,) =>{
   168→        e.stopPropagation();
   169→        if(!session) return openAuthModal();
   170→        console.log(journalId)
   171→        // mutationBookmark.mutate({journalId});
   172→        const response = await mutationBookmark.mutateAsync({journalId})
   173→        if(response.message === 'success'){
   174→            setBookmarkedMessage('Post was added to your Bookmarks')
   175→            setShowBookmarkedMessage(journalId);
   176→            setTimeout(() =>{
   177→                setShowBookmarkedMessage(null)
   178→                setBookmarkedMessage('')
   179→            }, 2500)
   180→        } else {
   181→            setBookmarkedMessage('Post was removed from your Bookmarks')
   182→            setShowBookmarkedMessage(journalId);
   183→            setTimeout(() =>{
   184→                setShowBookmarkedMessage(null)
   185→                setBookmarkedMessage('')
   186→            }, 2500)
   187→        }
   188→        console.log(response.message);
   189→    }
   190→
   191→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
   192→
   193→
   194→    const isLoadingMore = isFetchingNextPage || !hasNextPage;
   195→    useEffect(() =>{
   196→        if(inView && !isLoadingMore) {
   197→            fetchNextPage();
   198→        }
   199→    }, [inView, fetchNextPage, isLoadingMore])
   200→
   201→
   202→    useEffect(() => {
   203→       const handleClickOutside = (e) =>{
   204→        if(modalRef.current && !modalRef.current.contains(e.target)){
   205→            setPostIdSettings(null)
   206→        }
   207→       }
   208→       window.addEventListener('click', handleClickOutside)
   209→
   210→       return() => {
   211→        window.removeEventListener('click', handleClickOutside)
   212→       }
   213→    }, [])
   214→
   215→    useEffect(() =>{
   216→        const scroll = (e) =>{
   217→            setShowHeaders(!showHeaders)
   218→
   219→            if(timeOutRef.current){
   220→                clearTimeout(timeOutRef.current);
   221→            }
   222→            timeOutRef.current = setTimeout(() => {
   223→                setShowHeaders(showHeaders)
   224→            }, 100);
   225→        }
   226→        document.addEventListener('scroll', scroll, true);
   227→        return() =>{
   228→            if(timeOutRef.current){
   229→                clearTimeout(timeOutRef.current);
   230→            }
   231→            document.removeEventListener('scroll', scroll, true)
   232→        }
   233→    }, [])
   234→
   235→    useEffect(() =>{
   236→        console.log(data)
   237→    }, [data])
   238→
   239→    const journals = data?.pages?.flatMap((page) => page.data || []) || [];
