   338→                                                        {icon.likeAction && icon.likeAction(isLiked)}
   339→                                                    </div>
   340→                                                )}
   341→
   342→                                                {icon.commentAction && (
   343→                                                    <div onClick={(e) => icon.commentAction(e, journal.content,parsedContent.wholeText, journal.title, journal.users.id, journal.users.name, journal.users.image_url, journal.created_at, journal.id, journal.has_liked, journal.comment_count?.[0]?.count, journal.has_bookmarked, journal.like_count?.[0].count, journal.bookmark_count?.[0].count)} id="card-icons" className={icon.className}>
   344→                                                        {icon.label}
   345→                                                    </div>
   346→                                                )}
