    39→        const extractFromNodes = (nodes) =>{
    40→            nodes.forEach((node) => {
    41→                if(node.type === 'paragraph' || node.type === 'heading'){
    42→                    //extract text
    43→                    const textNodes = node.children?.filter((child) => child.type === "text") || [];
    44→                    const paragraphText = textNodes.map((child) => child.text).join(" "); //join all the array of text into one text form
    45→
    46→                    if(paragraphText.trim()) parsedData.text.push(paragraphText);
    47→
    48→                    const imageNodes = node.children?.filter((child) => child.type === 'image') || [];
    49→
    50→                    imageNodes.forEach((img) => {
    51→                        const imageData = {src: img.src, width: img.width, height: img.height};
    52→                        parsedData.images.push(imageData)
    53→                        if(!parsedData.firstImage) parsedData.firstImage = imageData; //check if firstImage has no image
    54→                    })
    55→                }
    56→
    57→                if (node.type === "image") {
    58→                    const imageData = { src: node.src, width: node.width, height: node.height };
    59→                    parsedData.images.push(imageData);
    60→                    if (!parsedData.firstImage) parsedData.firstImage = imageData;
    61→                 }
    62→
    63→                if(node.children) extractFromNodes(node.children);
    64→            });
    65→        }
    66→
    67→        extractFromNodes(children);
    68→
    69→        const combinedText = parsedData.text.join(' ').trim();
    70→        parsedData.wholeText = combinedText;
    71→        parsedData.slicedText = combinedText.length > 215 ? `${combinedText.substring(0, 215)}...` : combinedText;
    72→        
    73→        return parsedData; //return the parsedData
    74→        } catch (error) {
    75→            console.error('Error parsing content:', error);
    76→            return { text: [], images: [] };
    77→        }
    78→}
    79→export default ParseContent;
